import sqlite3
import json
import os
from flask import Flask, render_template, request, jsonify, session

app = Flask(__name__)
app.secret_key = os.urandom(32)
DB_PATH = "/tmp/aetheris.db"

def get_db():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def aegis_v4_filter(payload):
    if not payload or not isinstance(payload, str):
        return payload
    # Defense Layer 1: Keyword Stripping (strips once to 'prevent' injection)
    keywords = ['SELECT', 'UNION', 'FROM', 'WHERE', 'AND', 'OR', 'LIMIT', 'OFFSET', 'SLEEP']
    for word in keywords:
        payload = payload.replace(word, '')
        payload = payload.replace(word.lower(), '')

    # Defense Layer 2: Whitespace blocker
    if ' ' in payload:
        return "SECURITY_VIOLATION"

    # Defense Layer 3: Length constraint
    if len(payload) > 150:
        return "LIMIT_EXCEEDED"

    return payload

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/dashboard')
def dashboard():
    db = get_db()
    satellites = db.execute("SELECT * FROM satellites").fetchall()
    return render_template('dashboard.html', satellites=satellites)

@app.route('/api/v1/telemetry/debug/integrity', methods=['POST'])
def telemetry_integrity():
    # Hidden endpoint discovered via static JS
    data = request.get_json()
    if not data or 'batch_id' not in data or 'sort_metric' not in data:
        return jsonify({"error": "Missing parameters"}), 400

    batch_id = data.get('batch_id')
    sort_metric = data.get('sort_metric')

    # Apply Aegis-v4 Protection
    sanitized_sort = aegis_v4_filter(sort_metric)
    if sanitized_sort in ["SECURITY_VIOLATION", "LIMIT_EXCEEDED"]:
        return jsonify({"error": f"Aegis-v4 blocked request: {sanitized_sort}"}), 403

    try:
        db = get_db()
        # Vulnerable ORDER BY clause - buried in debug tool
        query = f"SELECT id, status, check_name, timestamp FROM telemetry_integrity WHERE batch_id = ? ORDER BY {sanitized_sort} ASC"
        results = db.execute(query, (batch_id,)).fetchall()

        return jsonify([dict(row) for row in results])
    except Exception as e:
        return jsonify({"error": "Database error", "msg": str(e)}), 500

@app.route('/manifests')
def manifests():
    db = get_db()
    manifests = db.execute("SELECT * FROM manifests").fetchall()
    return render_template('manifests.html', manifests=manifests)

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)

